def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random

    n, d = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def compute_hv(indices):
        if len(indices) == 0:
            return 0.0
        hv = pg.hypervolume(points[indices])
        return hv.compute(reference_point)

    def compute_contrib(idx, current_set):
        if len(current_set) == 0:
            return compute_hv([idx])
        combined = list(current_set) + [idx]
        return compute_hv(combined) - compute_hv(list(current_set))

    # Initialize population with random subsets
    population_size = 10
    population = []
    for _ in range(population_size):
        subset = set(random.sample(range(n), k))
        population.append((subset, compute_hv(list(subset))))

    best_subset, best_hv = max(population, key=lambda x: x[1])
    no_improve_count = 0

    for generation in range(50):
        # Selection: tournament selection
        new_population = []
        for _ in range(population_size):
            # Tournament of size 3
            contestants = random.sample(population, 3)
            winner = max(contestants, key=lambda x: x[1])
            new_population.append(winner)

        # Crossover: uniform crossover between two subsets
        offspring = []
        for i in range(0, population_size, 2):
            if i+1 < population_size:
                parent1, hv1 = new_population[i]
                parent2, hv2 = new_population[i+1]

                # Create child by taking union then reducing
                union_set = parent1 | parent2
                if len(union_set) > k:
                    # Greedy reduction to k points
                    while len(union_set) > k:
                        # Remove point with smallest contribution
                        worst = min(union_set, key=lambda x: compute_contrib(x, union_set - {x}))
                        union_set.remove(worst)
                child = union_set
                offspring.append((child, compute_hv(list(child))))

        # Mutation: try random swaps
        mutated = []
        for subset, hv in offspring:
            if random.random() < 0.7:  # Mutation probability
                current_set = set(subset)
                remaining = set(range(n)) - current_set

                # Try up to 5 random swaps
                for _ in range(5):
                    if not remaining:
                        break

                    s = random.choice(list(current_set))
                    r = random.choice(list(remaining))

                    new_set = (current_set - {s}) | {r}
                    new_hv = compute_hv(list(new_set))

                    if new_hv > hv:
                        current_set = new_set
                        remaining = (remaining - {r}) | {s}
                        hv = new_hv

                mutated.append((current_set, hv))
            else:
                mutated.append((subset, hv))

        # Elitism: keep best solution
        mutated.append((best_subset, best_hv))

        # Update population
        population = mutated
        current_best_subset, current_best_hv = max(population, key=lambda x: x[1])

        if current_best_hv > best_hv + 1e-10:
            best_subset, best_hv = current_best_subset, current_best_hv
            no_improve_count = 0
        else:
            no_improve_count += 1

        # Restart mechanism
        if no_improve_count >= 10:
            # Replace half population with random solutions
            num_replace = population_size // 2
            for i in range(num_replace):
                subset = set(random.sample(range(n), k))
                population[i] = (subset, compute_hv(list(subset)))
            no_improve_count = 0

    # Final local improvement
    current_set = best_subset
    remaining_set = set(range(n)) - current_set
    improved = True

    while improved:
        improved = False
        current_hv = compute_hv(list(current_set))

        # Try all possible single swaps
        for s in list(current_set):
            for r in remaining_set:
                new_set = (current_set - {s}) | {r}
                new_hv = compute_hv(list(new_set))

                if new_hv > current_hv + 1e-10:
                    current_set = new_set
                    remaining_set = (remaining_set - {r}) | {s}
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    return points[list(current_set)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq
    import pygmo as pg
    import random

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")
    if k == n:
        return points.copy()

    def compute_hv(indices):
        if len(indices) == 0:
            return 0.0
        hv = pg.hypervolume(points[indices])
        return hv.compute(reference_point)

    # Adaptive reference point adjustment
    def get_dynamic_reference(current_indices):
        if not current_indices:
            return reference_point
        selected_pts = points[current_indices]
        max_vals = np.max(selected_pts, axis=0)
        return np.maximum(max_vals * 1.05, reference_point)

    # Phase 1: Front-focused greedy selection
    selected = []
    remaining = set(range(n))

    # Start with extreme points in each dimension
    extreme_indices = []
    for dim in range(d):
        max_idx = np.argmax(points[:, dim])
        if max_idx not in extreme_indices:
            extreme_indices.append(max_idx)

    # Select up to min(k, d) extreme points
    num_extreme = min(k, len(extreme_indices))
    for i in range(num_extreme):
        idx = extreme_indices[i]
        if idx in remaining:
            selected.append(idx)
            remaining.remove(idx)

    # Greedy selection with dynamic reference
    while len(selected) < k and remaining:
        dynamic_ref = get_dynamic_reference(selected)

        # Compute contributions with current reference
        best_contrib = -1
        best_idx = None

        for idx in list(remaining)[:min(200, len(remaining))]:  # Limit candidates for speed
            temp_hv = pg.hypervolume(points[selected + [idx]])
            contrib = temp_hv.compute(dynamic_ref) - compute_hv(selected)
            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        if best_idx is not None:
            selected.append(best_idx)
            remaining.remove(best_idx)
        else:
            # Fallback: random selection from remaining
            selected.append(random.choice(list(remaining)))
            remaining.remove(selected[-1])

    # Phase 2: Iterative two-point exchange refinement
    current_set = set(selected)
    remaining_set = set(range(n)) - current_set
    max_iterations = 100
    iteration = 0

    while iteration < max_iterations:
        iteration += 1
        improved = False
        current_hv = compute_hv(list(current_set))

        # Try all two-point exchanges
        current_list = list(current_set)
        remaining_list = list(remaining_set)

        for i in range(len(current_list)):
            if improved:
                break
            for j in range(len(remaining_list)):
                if improved:
                    break

                s1, s2 = current_list[i], remaining_list[j]
                new_set = (current_set - {s1}) | {s2}
                new_hv = compute_hv(list(new_set))

                if new_hv > current_hv + 1e-10:
                    current_set = new_set
                    remaining_set = (remaining_set - {s2}) | {s1}
                    current_hv = new_hv
                    improved = True
                    break

        if not improved:
            break

    # Final greedy polish
    final_points = list(current_set)
    if len(final_points) < k:
        remaining_list = list(set(range(n)) - current_set)
        needed = k - len(final_points)
        additional = random.sample(remaining_list, min(needed, len(remaining_list)))
        final_points.extend(additional)

    return points[final_points]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, d = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")
    if k == n:
        return points.copy()

    # 计算单个点的超体积贡献
    def compute_contribution(selected_indices, candidate_idx):
        if len(selected_indices) == 0:
            # 计算单个点的超体积
            hv = pg.hypervolume(points[[candidate_idx]])
            return hv.compute(reference_point)

        # 计算添加候选点后的超体积
        combined_indices = selected_indices + [candidate_idx]
        hv_combined = pg.hypervolume(points[combined_indices])
        hv_current = pg.hypervolume(points[selected_indices])

        return hv_combined.compute(reference_point) - hv_current.compute(reference_point)

    # 初始化：选择极端点作为起点
    selected_indices = []

    # 首先选择每个维度上的极端点
    for dim in range(d):
        min_idx = np.argmin(points[:, dim])
        max_idx = np.argmax(points[:, dim])

        if min_idx not in selected_indices:
            selected_indices.append(min_idx)
        if max_idx not in selected_indices and len(selected_indices) < k:
            selected_indices.append(max_idx)

    # 贪心选择：每次选择对当前超体积贡献最大的点
    while len(selected_indices) < k:
        best_contribution = -float('inf')
        best_idx = -1

        # 遍历所有未选择的点
        for idx in range(n):
            if idx in selected_indices:
                continue

            contribution = compute_contribution(selected_indices, idx)

            if contribution > best_contribution:
                best_contribution = contribution
                best_idx = idx

        if best_idx != -1:
            selected_indices.append(best_idx)
        else:
            # 如果没有找到贡献为正的点，选择随机点
            remaining = [i for i in range(n) if i not in selected_indices]
            if remaining:
                selected_indices.append(random.choice(remaining))

    # 局部优化：尝试替换每个点以提升超体积
    improved = True
    while improved:
        improved = False

        for i in range(k):
            current_idx = selected_indices[i]
            best_replacement = current_idx
            best_hv = -float('inf')

            # 计算当前子集的超体积
            current_hv = pg.hypervolume(points[selected_indices]).compute(reference_point)

            # 尝试用其他点替换当前点
            for candidate in range(n):
                if candidate in selected_indices:
                    continue

                # 创建替换后的索引列表
                temp_indices = selected_indices.copy()
                temp_indices[i] = candidate

                # 计算新超体积
                temp_hv = pg.hypervolume(points[temp_indices]).compute(reference_point)

                if temp_hv > best_hv:
                    best_hv = temp_hv
                    best_replacement = candidate

            # 如果找到更好的替换
            if best_hv > current_hv + 1e-10:
                selected_indices[i] = best_replacement
                improved = True
                break

    return points[selected_indices]
